-- ELEKTRONİK - AKILLI TELEFONLAR (7) — 3 ürün
(85, 'Sony Xperia 1 VI 256GB Siyah', 'sony-xperia-1-vi-256gb-siyah', 'Sony Xperia 1 VI, 4K OLED ekranı ve Zeiss optikli kamera sistemiyle içerik üreticilerinin ve fotoğraf tutkunlarının tercihi.', '<p>Sony Xperia 1 VI, 6.5 inç 4K OLED ekranı ve Zeiss T* lensli üçlü kamera sistemiyle görsel kalitede rakipsiz bir deneyim sunar. Snapdragon 8 Gen 3 işlemcisi ve 5000 mAh büyük piliyle tam gün kesintisiz kullanım sağlar.</p><ul><li>6.5 inç 4K OLED, 120Hz ekran</li><li>Zeiss T* optikli 52 MP ana kamera</li><li>5000 mAh pil, 30W şarj</li><li>Snapdragon 8 Gen 3, 12 GB RAM</li><li>IP68 su ve toz geçirmezlik</li></ul>', 47999.00, 44999.00, 54, 'SNY-PHN-XP1VI', 'Sony', 7, 0.00, 0, TRUE, TRUE, '["sony","xperia","akıllı telefon","zeiss","android"]', 'Sony Xperia 1 VI', '4K OLED Ekranlı Zeiss Kameralı Telefon', NOW()),

(86, 'Motorola Edge 50 Pro 512GB Siyah', 'motorola-edge-50-pro-512gb-siyah', 'Motorola Edge 50 Pro, 165Hz pOLED ekranı ve 125W TurboPower şarjıyla hız ve konfor arayanlar için ideal mid-range amiral gemisi.', '<p>Motorola Edge 50 Pro, 6.7 inç pOLED curved ekranı ve 125W TurboPower şarj teknolojisiyle pili sadece 27 dakikada dolduran iddialı bir orta-üst segment akıllı telefondur. IP68 su geçirmezliği ve vegan deri arka yüzeyi premium tasarımı tamamlar.</p><ul><li>6.7 inç pOLED 165Hz Curved ekran</li><li>50 MP OIS ana kamera + 10 MP telefoto</li><li>125W TurboPower kablolu şarj</li><li>Snapdragon 7s Gen 2, 12 GB RAM</li><li>Vegan deri arka yüzey, IP68</li></ul>', 21999.00, 19999.00, 88, 'MOT-PHN-E50PRO', 'Motorola', 7, 0.00, 0, TRUE, FALSE, '["motorola","edge","akıllı telefon","oled","hızlı şarj"]', 'Motorola Edge 50 Pro', '165Hz OLED ve 125W Hızlı Şarj', NOW()),

(87, 'OPPO Find X7 Pro 512GB Seramik Beyaz', 'oppo-find-x7-pro-512gb-beyaz', 'OPPO Find X7 Pro, Hasselblad işbirliğiyle geliştirilen periskop kamera sistemi ve seramik arka yüzeyiyle premium segment için üretildi.', '<p>OPPO Find X7 Pro, 6.82 inç LTPO AMOLED ekranı ve Hasselblad onaylı dört kamera sistemiyle profesyonel fotoğrafçılık standartlarına yaklaşır. 100W SUPERVOOC şarj ve 50W kablosuz şarj desteğiyle enerji sorunu yaşatmaz.</p><ul><li>6.82 inç LTPO AMOLED, 120Hz</li><li>50 MP Hasselblad ana + 50 MP periskop telefoto</li><li>100W SUPERVOOC + 50W kablosuz şarj</li><li>Snapdragon 8 Gen 3, 16 GB RAM</li><li>Seramik arka panel, IP68</li></ul>', 39999.00, NULL, 37, 'OPP-PHN-FX7PRO', 'OPPO', 7, 0.00, 0, TRUE, FALSE, '["oppo","find x7","akıllı telefon","hasselblad","seramik"]', 'OPPO Find X7 Pro', 'Hasselblad Kameralı Seramik Premium', NOW()),

-- ELEKTRONİK - LAPTOP (8) — 2 ürün
(88, 'Microsoft Surface Laptop 5 Intel i7 512GB Platin', 'microsoft-surface-laptop-5-i7-512gb-platin', 'Surface Laptop 5, dokunmatik PixelSense ekranı ve ince alüminyum kasasıyla kurumsal ve yaratıcı kullanıcılara şık bir iş istasyonu sunar.', '<p>Microsoft Surface Laptop 5, 13.5 inç PixelSense dokunmatik ekranı ve Alcantara klavye yüzeyi ile hem estetik hem ergonomik bir deneyim sunar. Intel Core i7-1265U ve 16 GB RAM ile ofis ve içerik üretim görevlerini kolayca kaldırır.</p><ul><li>13.5 inç PixelSense 2256x1504 dokunmatik ekran</li><li>Intel Core i7-1265U, 16 GB LPDDR5X RAM</li><li>512 GB SSD, Thunderbolt 4</li><li>18 saate kadar pil ömrü</li><li>Alcantara klavye yüzeyi, Windows 11</li></ul>', 64999.00, 59999.00, 27, 'MSF-LAP-SL5I7PT', 'Microsoft', 8, 0.00, 0, TRUE, TRUE, '["microsoft","surface","laptop","windows","dokunmatik"]', 'Microsoft Surface Laptop 5', 'Şık Tasarım ve Dokunmatik Ekran', NOW()),

(89, 'HP Spectre x360 14 Intel i7 OLED 2-in-1', 'hp-spectre-x360-14-i7-oled-2in1', 'HP Spectre x360 14, 360 derece dönen OLED ekranı ve Intel Evo sertifikasıyla laptop ve tablet deneyimini tek cihazda birleştiriyor.', '<p>HP Spectre x360 14, 2.8K OLED dokunmatik ekranı 360 derece katlanabilir tasarımla laptop, tablet, stand ve çadır modlarında kullanılmasını sağlar. Intel Evo sertifikası anlık uyandırma ve üstün pil ömrünü garanti eder.</p><ul><li>14 inç 2.8K OLED dokunmatik, 120Hz</li><li>Intel Core i7-1355U, 16 GB RAM</li><li>1 TB SSD, Thunderbolt 4</li><li>17 saate kadar pil ömrü</li><li>HP Sure View gizlilik ekranı, Intel Evo</li></ul>', 71999.00, NULL, 19, 'HPQ-LAP-SX36014', 'HP', 8, 0.00, 0, TRUE, FALSE, '["hp","spectre","2-in-1","oled","laptop"]', 'HP Spectre x360 14 OLED', 'Dönüştürülebilir OLED 2-in-1 Laptop', NOW()),

-- ELEKTRONİK - TABLET (9) — 2 ürün
(90, 'Microsoft Surface Pro 10 Intel Core Ultra 7 Wi-Fi', 'microsoft-surface-pro-10-core-ultra7-wifi', 'Surface Pro 10, ince ve hafif gövdesinde Intel Core Ultra 7 çipi ve yapay zeka destekli Windows 11 ile iş gücü platformu.', '<p>Microsoft Surface Pro 10, ince tasarımına rağmen Intel Core Ultra 7 165H işlemcisi ve NPU donanımlı yapay zeka desteğiyle ofis verimliliğini zirveye taşır. Detachable klavye ve Surface Slim Pen 2 ile tam masaüstü deneyimi sağlar.</p><ul><li>13 inç PixelSense Flow 120Hz ekran</li><li>Intel Core Ultra 7 165H, 16 GB RAM</li><li>512 GB SSD, Thunderbolt 4</li><li>Yapay Zeka destekli NPU işlemci</li><li>USB-A, USB-C, Surface Connect port</li></ul>', 52999.00, NULL, 31, 'MSF-TAB-SP10CU7', 'Microsoft', 9, 0.00, 0, TRUE, FALSE, '["microsoft","surface pro","tablet","windows","yapay zeka"]', 'Microsoft Surface Pro 10', 'Yapay Zeka Destekli 2-in-1 Tablet', NOW()),

(91, 'Xiaomi Pad 6S Pro 12.4" 512GB Wi-Fi', 'xiaomi-pad-6s-pro-12-4-512gb-wifi', 'Xiaomi Pad 6S Pro, 3K ekranı ve Snapdragon 8 Gen 2 çipiyle yüksek çözünürlüklü içerik tüketimi ve çizim için güçlü bir Android tablettir.', '<p>Xiaomi Pad 6S Pro, 12.4 inç 3K LCD ekranı ve Snapdragon 8 Gen 2 işlemcisiyle grafik yoğun uygulamalarda akıcı bir deneyim sunar. 144Hz yenileme hızı ve Xiaomi Smart Pen 2 ile hem yaratıcı çalışmalar hem de not alma kolaylaşır.</p><ul><li>12.4 inç 3K LCD, 144Hz</li><li>Snapdragon 8 Gen 2, 12 GB RAM</li><li>512 GB depolama, microSD desteği</li><li>10000 mAh pil, 120W şarj</li><li>Dört hoparlör, Dolby Atmos, HiRes Audio</li></ul>', 24999.00, 22499.00, 59, 'XMI-TAB-P6SPR12', 'Xiaomi', 9, 0.00, 0, TRUE, FALSE, '["xiaomi","pad","tablet","3k","android"]', 'Xiaomi Pad 6S Pro', '3K 144Hz Ekranlı Güçlü Android Tablet', NOW()),

