(92, 'Sennheiser Momentum 4 Wireless Siyah', 'sennheiser-momentum-4-wireless-siyah', 'Sennheiser Momentum 4, 60 saatlik pil ömrü ve Adaptive ANC teknolojisiyle uzun seyahatler için müzisyenler kalibresinde ses sunar.', '<p>Sennheiser Momentum 4, 42mm özel geliştirme transducer ile kulak üstü kulaklıkta müzik yayıncısı doğruluğunu sağlar. 60 saate kadar pil ömrü ve Adaptive ANC sistemi ile uçuş ve toplu taşıma ortamlarında sessiz bir dinleme deneyimi yaşatır.</p><ul><li>60 saate kadar pil ömrü (ANC dahil)</li><li>Sennheiser Adaptive ANC</li><li>42mm özel transducer</li><li>Çoklu cihaz bağlantısı (Multipoint)</li><li>Katlanabilir tasarım, deri yastık</li></ul>', 11499.00, 9999.00, 73, 'SEN-AUD-MM4WLK', 'Sennheiser', 10, 0.00, 0, TRUE, TRUE, '["sennheiser","kulaklık","anc","kablosuz","hi-fi"]', 'Sennheiser Momentum 4', '60 Saat Pilli Premium Kulaklık', NOW()),

(93, 'Samsung Galaxy Buds3 Pro Gümüş TWS Kulaklık', 'samsung-galaxy-buds3-pro-gumus-tws', 'Galaxy Buds3 Pro, Intelligent ANC ve 360 Ses teknolojisiyle Samsung ekosistemiyle tam entegre çalışan kulak içi kulaklık.', '<p>Samsung Galaxy Buds3 Pro, ANC ve Hi-Fi ses kalitesini kolayca taşınabilir kulak içi formatta sunar. Blade design ve LED şerit tasarımı göze çarpan bir estetik yaratırken 360 Ses ve SSC HiFi codec üstün ses deneyimi sağlar.</p><ul><li>Intelligent ANC ve ortam sesi</li><li>360 Ses (Spatial Audio)</li><li>SSC HiFi codec desteği</li><li>6 saat pil + kılıfla 26 saat</li><li>IP57 toz ve su direnci</li></ul>', 8999.00, NULL, 106, 'SAM-AUD-GB3PRGM', 'Samsung', 10, 0.00, 0, TRUE, FALSE, '["samsung","galaxy buds","tws","anc","spatial audio"]', 'Samsung Galaxy Buds3 Pro', 'Hi-Fi ve ANC Özellikli TWS Kulaklık', NOW()),

