(94, 'Patagonia Capilene Cool Daily Erkek Tişört Lacivert', 'patagonia-capilene-cool-daily-erkek-tisort', 'Patagonia Capilene Cool Daily, geri dönüştürülmüş polyester ve doğal koku kontrolüyle outdoor ve günlük kullanımda ideal teknik tişört.', '<p>Patagonia Capilene Cool Daily, %100 geri dönüştürülmüş polyester ve Polygiene® koku önleyici teknolojisiyle hem çevre dostu hem de performans odaklı bir tişörttür. Güneş koruması ve hafif yapısıyla trekking, seyahat ve günlük kullanıma eşit uyum sağlar.</p><ul><li>%100 geri dönüştürülmüş polyester</li><li>Polygiene® kalıcı koku önleme</li><li>UPF 25+ güneş koruması</li><li>Hafif, hızlı kuruyan kumaş</li><li>Fair Trade Sertifikalı üretim</li></ul>', 1499.00, NULL, 192, 'PAT-TSH-CPCDLYLN', 'Patagonia', 11, 0.00, 0, TRUE, FALSE, '["patagonia","tişört","outdoor","sürdürülebilir","dri-fit"]', 'Patagonia Capilene Cool Daily', 'Sürdürülebilir Teknik Outdoor Tişört', NOW()),

(95, 'Lacoste Classic Pique Polo Tişört Beyaz L.12.12', 'lacoste-classic-pique-polo-l1212-beyaz', 'Lacoste L.12.12, 1933''ten bu yana üretilen ikonik timsah logolu klasik pike polo tişört.', '<p>Lacoste L.12.12, özel baskı desenli pike kumaşı ve ikonik yeşil timsah logosunun göğüse nakışıyla sade şıklığın simgesidir. Slim fit kesim ve örgü polo yaka, iş casual kombinlerden hafta sonu buluşmalarına kadar her ortama uygundur.</p><ul><li>%100 Pique pamuk, sıkı dokuma</li><li>Slim fit, klasik polo yaka</li><li>Ikonik timsah nakış detayı</li><li>Yandan yırtmaçlı alt etek</li><li>Makine yıkama uyumlu, renk haslığı yüksek</li></ul>', 2199.00, 1799.00, 145, 'LAC-TSH-CL1212WH', 'Lacoste', 11, 0.00, 0, TRUE, FALSE, '["lacoste","polo","tişört","klasik","pamuk"]', 'Lacoste Classic Polo L.12.12', 'Ikonik Timsah Logolu Polo Tişört', NOW()),

