(96, 'New Balance Athletics Fleece Kapüşonlu Sweatshirt Siyah', 'new-balance-athletics-fleece-hoodie-siyah', 'New Balance Athletics Fleece Hoodie, ağır gramaj pamuklu fleece ve büyük ön logo baskısıyla spor heritage stilini yansıtır.', '<p>New Balance Athletics koleksiyonundan bu hoodie, ağır gramaj French terry fleece kumaşı ve bold NB logo baskısıyla hem sokak stiline hem de spor ortamına hitap eder. Kangaroo cep ve ayarlanabilir kapüşon pratik kullanım sağlar.</p><ul><li>%80 pamuk, %20 polyester ağır gramaj fleece</li><li>Bold NB Athletics logo baskı</li><li>Kangaroo ön cep</li><li>Elastik bileklik ve bel bandı</li><li>Oversize fit, unisex tasarım</li></ul>', 2399.00, NULL, 117, 'NBL-SWT-ATFLHDK', 'New Balance', 12, 0.00, 0, TRUE, FALSE, '["new balance","hoodie","sweatshirt","fleece","athletics"]', 'New Balance Athletics Hoodie', 'Spor Heritage Stilinde Ağır Gramaj Hoodie', NOW()),

(97, 'Carhartt WIP Chase Crew Neck Sweatshirt Haki', 'carhartt-wip-chase-crew-sweatshirt-haki', 'Carhartt WIP Chase Sweatshirt, sağlam pamuklu fransız havlu dokusu ve iş etiketli logo nakışıyla workwear estetiğini streetwear''a taşıyor.', '<p>Carhartt WIP Chase, %100 pamuk Molleton kumaşından üretilmiş crew neck sweatshirt; iş kıyafeti dayanıklılığını şehir stiline uyarlar. Küçük C logosu nakışı ve beyaz şerit detayıyla minimalist ama ayırt edici bir görünüm sunar.</p><ul><li>%100 ağır gramaj pamuk Molleton</li><li>Küçük C Logo nakış + şerit detay</li><li>Crew neck, bant yaka</li><li>Ribana bileklik ve bel</li><li>Regular fit, unisex</li></ul>', 2699.00, NULL, 94, 'CRH-SWT-CHSCRHK', 'Carhartt', 12, 0.00, 0, TRUE, FALSE, '["carhartt","sweatshirt","crew neck","workwear","streetwear"]', 'Carhartt WIP Chase Crew', 'Workwear Dayanıklılığı Sokak Stilinde', NOW()),

