(98, 'Patagonia Quandary Pants Erkek Outdoor Pantolon Gri', 'patagonia-quandary-pants-erkek-gri', 'Patagonia Quandary Pants, hafif ve streçli DWR kaplı nylon dokusuyla climbing, trekking ve günlük kullanımda çok yönlü outdoor pantolonudur.', '<p>Patagonia Quandary Pants, Fair Trade sertifikalı üretimi ve DWR kaplı hafif nylon kumasıyla trekking, kayalık arazi ve şehir kullanımına eşit uyum sağlar. Esnek bel bandı ve diz altı artikülasyonu tam hareket özgürlüğü sağlar.</p><ul><li>%95 nylon, %5 elastan, DWR kaplama</li><li>Gizli kemer döngüsü, iç bel ayarı</li><li>4 yönlü streç, diz artikülasyonu</li><li>Fermuarlı kalça ve arka cep</li><li>Fair Trade Sertifikalı üretim</li></ul>', 3199.00, NULL, 74, 'PAT-PNT-QNDRYPGR', 'Patagonia', 13, 0.00, 0, TRUE, FALSE, '["patagonia","outdoor","pantolon","trekking","streç"]', 'Patagonia Quandary Pants', 'Çok Yönlü DWR Kaplı Outdoor Pantolonu', NOW()),

(99, 'G-Star RAW 3301 Slim Fit Erkek Denim Pantolon Koyu Mavi', 'g-star-raw-3301-slim-fit-erkek-denim', 'G-Star RAW 3301, raw denim kültürünü slim fit kesim ve 3D biçimlendirilmiş dikiş teknolojisiyle modern günlük stile taşıyor.', '<p>G-Star RAW 3301, 3D biçimlendirilmiş dikiş tekniği sayesinde vücut siluetine mükemmel uyum sağlayan slim fit bir denim pantolondur. Yıkanmamış (raw) 12 oz selvedge denim zamanla kullanıcının vücuduna göre şekil alarak kişiselleşir.</p><ul><li>12 oz ham selvedge denim</li><li>3D contour dikişi, slim fit</li><li>Siyah bant detayı arka cep</li><li>Orta bel yüksekliği, tapered bacak</li><li>Koyu mavi (Dark Aged wash)</li></ul>', 2999.00, 2499.00, 108, 'GST-PNT-3301SLDB', 'G-Star RAW', 13, 0.00, 0, TRUE, FALSE, '["g-star","denim","pantolon","slim","raw"]', 'G-Star RAW 3301 Slim', '3D Dikiş Teknolojili Premium Denim', NOW()),

