(100, 'Hoka Clifton 9 Erkek Koşu Ayakkabısı Gece Mavisi', 'hoka-clifton-9-erkek-gece-mavisi', 'Hoka Clifton 9, tam uzunlukta EVA köpük ara taban ve meta-rocker geometrisiyle maraton mesafelerinde koşucuların en yüksek konfor seçimi.', '<p>Hoka Clifton 9, belirgin düz taban tasarımı ve tam uzunluk EVA köpüğüyle uzun mesafe koşularında yorulmadan ilerlemenizi sağlar. Meta-Rocker geometrisi, topuktan parmak ucuna doğal bir yuvarlanma hareketi yaratarak enerji kaybını azaltır.</p><ul><li>Tam uzunlukta hafif EVA ara taban</li><li>Meta-Rocker geometrisi</li><li>Engineered mesh üst, nefes alabilir</li><li>Ezilmeye dayanıklı topuk kumaşı</li><li>Erkek: 40-47 beden aralığı</li></ul>', 6499.00, NULL, 87, 'HOK-SNK-CLF9NVY', 'Hoka', 15, 0.00, 0, TRUE, FALSE, '["hoka","clifton","koşu","maximal","spor ayakkabı"]', 'Hoka Clifton 9', 'Maksimal Yastıklama ile Uzun Mesafe Konforu', NOW()),

(101, 'Brooks Ghost 16 Erkek Koşu Ayakkabısı Beyaz/Mavi', 'brooks-ghost-16-erkek-beyaz-mavi', 'Brooks Ghost 16, DNA LOFT v3 köpük ara taban ve 3D Fit Print teknolojisiyle nötr koşucular için birinci sınıf koşu deneyimi sunar.', '<p>Brooks Ghost 16, güncellenmiş DNA LOFT v3 köpük formülüyle daha yumuşak ve daha tepkili bir koşu deneyimi sunacak şekilde yeniden tasarlandı. 3D Fit Print teknolojisi, dikişsiz bir üst yapı ile ayak şekillerine kusursuz uyum sağlar.</p><ul><li>DNA LOFT v3 köpük ara taban</li><li>3D Fit Print dikişsiz üst</li><li>Omega Flex Grooves esnek taban</li><li>Segmentli çarpışma bölgesi</li><li>Erkek/Kadın geniş beden aralığı</li></ul>', 5999.00, NULL, 61, 'BRK-SNK-GH16WBL', 'Brooks', 15, 0.00, 0, TRUE, FALSE, '["brooks","ghost","koşu","dna loft","spor ayakkabı"]', 'Brooks Ghost 16', 'Nötr Koşucular İçin Premium Koşu Ayakkabısı', NOW()),

-- AYAKKABI - SNEAKER (16) — 2 ürün
(102, 'Nike Dunk Low Retro Panda Siyah/Beyaz', 'nike-dunk-low-retro-panda-siyah-beyaz', 'Nike Dunk Low Retro Panda, ikonik siyah-beyaz renk blok tasarımıyla tüm zamanların en çok aranan sneaker silüetlerinden biri olmaya devam ediyor.', '<p>Nike Dunk Low, 1985''te basketbol sahalarında doğan ve bugün sneaker kültürünün tartışmasız simgelerinden biri haline gelen tasarımını aynen korur. Panda olarak bilinen siyah-beyaz colorway temiz ve çok yönlü görünümüyle her kombin ile uyum sağlar.</p><ul><li>Deri ve sentetik deri üst kısım</li><li>Daha ince dil ve bileklik, düşük profil</li><li>Nike Air yastıklaması (heel)</li><li>Kauçuk dış taban</li><li>Ikonik Swoosh ve top-cap detayı</li></ul>', 3999.00, NULL, 213, 'NKE-SNK-DKLWPND', 'Nike', 16, 0.00, 0, TRUE, TRUE, '["nike","dunk low","panda","sneaker","retro"]', 'Nike Dunk Low Retro Panda', 'Tüm Zamanların En İkonik Sneaker Colorway''i', NOW()),

(103, 'Reebok Classic Leather Gri/Gum Erkek Sneaker', 'reebok-classic-leather-gri-gum-erkek', 'Reebok Classic Leather, 1983''ten beri değişmeyen deri üst ve lastik taban kombinasyonuyla retro sneaker segmentinin vazgeçilmezi.', '<p>Reebok Classic Leather, orijinal 1983 koşu ayakkabısı tasarımından ilham alan düz profili ve tam tahıl deri üst kısımıyla vintage sneaker estetiğini günümüze taşır. Gum taban detayı otantik 80ler stilini tamamlar.</p><ul><li>Tam tahıl deri üst kısım</li><li>EV yastıklama ara taban</li><li>Gum lastik dış taban</li><li>Klasik düşük profil tasarım</li><li>Unisex, geniş beden aralığı</li></ul>', 2699.00, 2199.00, 155, 'RBK-SNK-CLLTGRGM', 'Reebok', 16, 0.00, 0, TRUE, FALSE, '["reebok","classic leather","retro","sneaker","gum"]', 'Reebok Classic Leather Gri/Gum', '80ler Retro Estetiğinin Deri Klasiği', NOW()),

-- EV & YAŞAM (4) — 3 ürün
(104, 'iRobot Roomba j9+ Akıllı Robot Süpürge', 'irobot-roomba-j9-plus-akilli-robot-supurge', 'iRobot Roomba j9+, kendi kendini boşaltan şarj tabanı ve PrecisionVision navigasyonuyla tam otomatik ev temizliği sağlar.', '<p>iRobot Roomba j9+, PrecisionVision™ navigasyon sistemi sayesinde mobilya ve kablo gibi engelleri gerçek zamanlı olarak tanıyarak kaçınır. Clean Base® Otomatik Kir Boşaltma birimi, pis su dolu torbayı 60 güne kadar taşımanızı sağlar.</p><ul><li>PrecisionVision™ engellerden kaçınma</li><li>Clean Base® 60 güne kadar otomatik boşaltma</li><li>3 aşamalı temizlik sistemi</li><li>Uygulama ve sesli asistan kontrolü</li><li>Wi-Fi bağlantısı, zamanlama</li></ul>', 22999.00, 19999.00, 21, 'IRB-HOM-RBJ9PLUS', 'iRobot', 4, 0.00, 0, TRUE, TRUE, '["irobot","roomba","robot süpürge","akıllı ev","otomasyon"]', 'iRobot Roomba j9+', 'Kendi Kendini Boşaltan Robot Süpürge', NOW()),

(105, 'Smeg FAB28 Retro Buzdolabı Krem', 'smeg-fab28-retro-buzdolabi-krem', 'Smeg FAB28, 50ler İtalyan tasarım estetiğini A++ enerji sınıfıyla birleştiren dekoratif ve fonksiyonel tek kapılı buzdolabı.', '<p>Smeg FAB28, ikonik yuvarlak hatları ve pastel renk seçenekleriyle mutfağınıza estetik bir odak noktası olur. Dahili fanı sayesinde eşit soğutma sağlar, üstteki derin dondurucu bölme ile günlük saklama ihtiyaçlarınızı karşılar.</p><ul><li>270 litre net hacim (222L soğutucu + 26L dondurucu)</li><li>A++ enerji sınıfı</li><li>Dahili fan, eşit soğutma</li><li>Ayarlanabilir cam raflar</li><li>2 yıl resmi Smeg garantisi</li></ul>', 34999.00, NULL, 14, 'SMG-HOM-FAB28CR', 'Smeg', 4, 0.00, 0, TRUE, FALSE, '["smeg","buzdolabı","retro","tasarım","mutfak"]', 'Smeg FAB28 Retro Buzdolabı', '50ler İtalyan Tasarımı ile A++ Soğutma', NOW()),

(106, 'Weber Spirit E-315 3 Gözlü Gazlı Izgarası', 'weber-spirit-e-315-3-goz-gazli-izgara', 'Weber Spirit E-315, üç adet bağımsız kontrol edilebilir yanıcısı ve GS4 ızgara sistemiyle her mevsim mükemmel barbeküyü garantiler.', '<p>Weber Spirit E-315, paslanmaz çelik GS4 yanıcıları ve porselen emaye kapağıyla uzun ömürlü ve verimli bir ızgara deneyimi sunar. Yan tezgah, baharatlar ve araçlar için ek alan sağlarken Snap-Jet ateşleme sistemi güvenli tutuşma sağlar.</p><ul><li>3 adet GS4 yüksek performanslı yanıcı</li><li>Toplam 10500 kcal/h ısı çıkışı</li><li>Porselen emaye kapak ve ızgara ızgarası</li><li>Snap-Jet bağımsız ateşleme sistemi</li><li>10 yıl yanıcı garantisi</li></ul>', 17999.00, 15999.00, 18, 'WBR-HOM-SPE315', 'Weber', 4, 0.00, 0, TRUE, FALSE, '["weber","izgara","barbeku","gazlı","outdoor"]', 'Weber Spirit E-315 Gazlı Izgara', 'Üç Yanıcılı Profesyonel Ev Izgarası', NOW()),

-- SPOR & OUTDOOR (5) — 3 ürün
(107, 'Garmin Fenix 7X Solar GPS Outdoor Saat Titanium', 'garmin-fenix-7x-solar-gps-outdoor-saat', 'Garmin Fenix 7X Solar, güneş enerjisiyle şarj özelliği ve multi-sport GPS takibiyle zorlu outdoor koşulları için tasarlanmış premium akıllı saat.', '<p>Garmin Fenix 7X Solar, Power Glass™ güneş şarj lensleri sayesinde GPS modunda 37 güne kadar pil ömrü sunar. Titanyum kasa ve safir ekranıyla yüksek dayanıklılık gerektiren tırmanış, triatlon ve ski gibi disiplinlerde güvenilir bir eşlik eder.</p><ul><li>Power Glass™ güneş şarj lensi</li><li>37 güne kadar GPS pil ömrü</li><li>Titanyum kasa + Safir ekran</li><li>Multi-band GPS, çoklu spor profili</li><li>100 metre su direnci, dalış desteği</li></ul>', 23999.00, NULL, 26, 'GRM-SPT-FNX7XSL', 'Garmin', 5, 0.00, 0, TRUE, TRUE, '["garmin","fenix","gps saat","outdoor","solar"]', 'Garmin Fenix 7X Solar', 'Güneş Enerjili Titanium Outdoor GPS Saati', NOW()),

(108, 'Black Diamond Crag Daddy 35L Tırmanış Çantası', 'black-diamond-crag-daddy-35l-tirmanis-cantasi', 'Black Diamond Crag Daddy 35L, haul kapı ve ip bölmesiyle kaya tırmanışı için özel tasarlanmış teknik sırt çantasıdır.', '<p>Black Diamond Crag Daddy 35L, tırmanış ekipmanınızı taşımayı kolaylaştıran özel haul kapısı ve ayrı ip bölmesiyle kaya tırmanışı için optimize edilmiş bir sırt çantasıdır. Bölümlere ayrılmış ana hacmi ve dış bağlantı noktaları ile ekipman organizasyonunu basitleştirir.</p><ul><li>35 litrelik hacim, tırmanış organize bölmeler</li><li>Haul kapısı (alt açılım)</li><li>Ayrı ip bölmesi</li><li>Karabina askı döngüleri</li><li>Hydration uyumlu, sternum straps</li></ul>', 4299.00, NULL, 43, 'BLD-SPT-CD35TRN', 'Black Diamond', 5, 0.00, 0, TRUE, FALSE, '["black diamond","tırmanış","sırt çantası","outdoor","crag"]', 'Black Diamond Crag Daddy 35L', 'Kaya Tırmanışı İçin Teknik Sırt Çantası', NOW()),

(109, 'Suunto Race Titanium GPS Koşu ve Triatlon Saati', 'suunto-race-titanium-gps-kos-saat', 'Suunto Race Titanium, AMOLED ekran ve 85 saatlik GPS pil ömrüyle ultra maratonlarda ve triatlonlarda güvenilir yol arkadaşı.', '<p>Suunto Race Titanium, canlı AMOLED dokunmatik ekranı ve 85 saate kadar GPS pil ömrüyle ultra mesafe koşucuları ve iron-man triatletlerine yönelik tasarlanmıştır. Otomatik segment algılama ve gerçek zamanlı koşu güç metrikleri antrenman kalitesini artırır.</p><ul><li>AMOLED dokunmatik ekran</li><li>85 saate kadar GPS pil ömrü</li><li>Titanyum kasa, 100m su geçirmezlik</li><li>Otomatik segment ve tempo takibi</li><li>Suunto App ile antrenman analizi</li></ul>', 16999.00, NULL, 31, 'SUT-SPT-RACETITGP', 'Suunto', 5, 0.00, 0, TRUE, FALSE, '["suunto","gps saat","triatlon","koşu","titanium"]', 'Suunto Race Titanium', '85 Saat GPS Pilli Triatlon ve Ultra Koşu Saati', NOW());

